    private async Task<IJSObjectReference> GetModuleAsync()
    {
        _module ??= await _jsRuntime.InvokeAsync<IJSObjectReference>("import", "./js/indexedDb.js");
        return _module;
    }

    public async Task InitializeAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeAsync<bool>("openDb");
    }

    public async Task<List<ConstructionSite>> GetSitesAsync()
    {
        var module = await GetModuleAsync();
        var results = await module.InvokeAsync<JsonElement>("getAll", "sites");
        return Deserialize<List<ConstructionSite>>(results);
    }

    public async Task<ConstructionSite?> GetSiteAsync(string id)
    {
        var module = await GetModuleAsync();
        var result = await module.InvokeAsync<JsonElement?>("getById", "sites", id);
        if (result == null || result.Value.ValueKind == JsonValueKind.Null) return null;
        return Deserialize<ConstructionSite>(result.Value);
    }

    public async Task SaveSiteAsync(ConstructionSite site)
    {
        var module = await GetModuleAsync();
        var obj = SerializeToElement(site);
        await module.InvokeAsync<bool>("put", "sites", obj);
    }

    public async Task DeleteSiteAsync(string id)
    {
        var module = await GetModuleAsync();
        await module.InvokeAsync<bool>("deleteRecord", "sites", id);
    }

    public async Task<List<Inspection>> GetInspectionsAsync()
    {
        var module = await GetModuleAsync();
        var results = await module.InvokeAsync<JsonElement>("getAll", "inspections");
        return Deserialize<List<Inspection>>(results);
    }

    public async Task<List<Inspection>> GetInspectionsBySiteAsync(string siteId)
    {
        var module = await GetModuleAsync();
        var results = await module.InvokeAsync<JsonElement>("getByIndex", "inspections", "siteId", siteId);
        return Deserialize<List<Inspection>>(results);
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var module = await GetModuleAsync();
        var result = await module.InvokeAsync<JsonElement?>("getById", "inspections", id);
        if (result == null || result.Value.ValueKind == JsonValueKind.Null) return null;
        return Deserialize<Inspection>(result.Value);
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var module = await GetModuleAsync();
        var obj = SerializeToElement(inspection);
        await module.InvokeAsync<bool>("put", "inspections", obj);
    }

    public async Task DeleteInspectionAsync(string id)
    {
        var module = await GetModuleAsync();
        await module.InvokeAsync<bool>("deleteRecord", "inspections", id);
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var module = await GetModuleAsync();
        var results = await module.InvokeAsync<JsonElement>("getByIndex", "inspections", "isSynced", false);
        return Deserialize<List<Inspection>>(results);
    }

    public async Task MarkAsSyncedAsync(string inspectionId)
    {
        var inspection = await GetInspectionAsync(inspectionId);
        if (inspection != null)
        {
            inspection.IsSynced = true;
            await SaveInspectionAsync(inspection);
        }
    }

    private static T Deserialize<T>(JsonElement element)
    {
        return JsonSerializer.Deserialize<T>(element.GetRawText(), JsonOptions) ?? default!;
    }

    private static JsonElement SerializeToElement<T>(T obj)
    {
        var json = JsonSerializer.Serialize(obj, JsonOptions);
        return JsonDocument.Parse(json).RootElement.Clone();
    }

    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        PropertyNameCaseInsensitive = true
    };

    public async ValueTask DisposeAsync()
    {
        if (_module != null)
        {
            await _module.DisposeAsync();
        }
    }
}
