+using System.Net.Http.Json;
+using SiteInspector.Client.Models;
+
+namespace SiteInspector.Client.Services;
+
+public class SyncService : ISyncService
+{
+    private readonly ILocalStorageService _storage;
+    private readonly HttpClient _httpClient;
+    private readonly ConnectivityService _connectivity;
+
+    public event Action<SyncStatus>? OnStatusChanged;
+    public SyncStatus CurrentStatus { get; private set; } = SyncStatus.Idle;
+    public int PendingCount { get; private set; }
+
+    public SyncService(ILocalStorageService storage, HttpClient httpClient, ConnectivityService connectivity)
+    {
+        _storage = storage;
+        _httpClient = httpClient;
+        _connectivity = connectivity;
+    }
+
+    public async Task SyncAsync()
+    {
+        if (!_connectivity.IsOnline)
+        {
+            SetStatus(SyncStatus.Offline);
+            return;
+        }
+
+        SetStatus(SyncStatus.Syncing);
+
+        try
+        {
+            var unsynced = await _storage.GetUnsyncedInspectionsAsync();
+            PendingCount = unsynced.Count;
+
+            if (unsynced.Count == 0)
+            {
+                SetStatus(SyncStatus.Success);
+                return;
+            }
+
+            var response = await _httpClient.PostAsJsonAsync("/api/inspections/sync", unsynced);
+
+            if (response.IsSuccessStatusCode)
+            {
+                foreach (var inspection in unsynced)
+                {
+                    await _storage.MarkAsSyncedAsync(inspection.Id);
+                }
+                PendingCount = 0;
+                SetStatus(SyncStatus.Success);
+            }
+            else
+            {
+                SetStatus(SyncStatus.Failed);
+            }
+        }
+        catch
+        {
+            SetStatus(SyncStatus.Failed);
+        }
+    }
+
+    private void SetStatus(SyncStatus status)
+    {
+        CurrentStatus = status;
+        OnStatusChanged?.Invoke(status);
+    }
+}
+

