@page "/"
@inject ILocalStorageService Storage
@inject ISyncService SyncService
@inject ConnectivityService Connectivity
@inject NavigationManager Navigation

<div class="page-header">
    <h1>Construction Sites</h1>
    <button class="btn-primary" @onclick="NavigateToNewSite">+ Add Site</button>
</div>

<div class="sync-bar">
    <span class="connectivity-dot @(Connectivity.IsOnline ? "online" : "offline")"></span>
    <span>@(Connectivity.IsOnline ? "Online" : "Offline")</span>
    @if (SyncService.PendingCount > 0)
    {
        <span class="pending-badge">@SyncService.PendingCount pending</span>
    }
</div>

@if (sites == null)
{
    <p class="loading">Loading...</p>
}
else if (sites.Count == 0)
{
    <div class="empty-state">
        <p>No construction sites yet.</p>
        <p>Tap "Add Site" to get started.</p>
    </div>
}
else
{
    <div class="site-list">
        @foreach (var site in sites)
        {
            <div class="site-card" @onclick="() => NavigateToSite(site.Id)">
                <div class="site-card-content">
                    <h3>@site.Name</h3>
                    <p class="site-address">@site.Address</p>
                    <p class="site-count">@(inspectionCounts.GetValueOrDefault(site.Id, 0)) inspections</p>
                </div>
                <span class="chevron">›</span>
            </div>
        }
    </div>
}

@code {
    private List<ConstructionSite>? sites;
    private Dictionary<string, int> inspectionCounts = new();

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        await Connectivity.InitializeAsync();
        await LoadData();

        SyncService.OnStatusChanged += _ => InvokeAsync(StateHasChanged);
        Connectivity.OnConnectivityChanged += async online =>
        {
            if (online) await SyncService.SyncAsync();
            await InvokeAsync(StateHasChanged);
        };
    }

    private async Task LoadData()
    {
        sites = await Storage.GetSitesAsync();
        inspectionCounts.Clear();
        foreach (var site in sites)
        {
            var inspections = await Storage.GetInspectionsBySiteAsync(site.Id);
            inspectionCounts[site.Id] = inspections.Count;
        }
    }

    private void NavigateToNewSite() => Navigation.NavigateTo("/site/new");
    private void NavigateToSite(string id) => Navigation.NavigateTo($"/site/{id}");
}

