    </div>
    <div class="form-group">
        <label>Address</label>
        <input type="text" @bind="site.Address" placeholder="Enter address" class="form-input" />
    </div>
    <button class="btn-primary btn-full" @onclick="Save" disabled="@string.IsNullOrWhiteSpace(site.Name)">
        Save Site
    </button>
</div>

@code {
    private ConstructionSite site = new();

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(site.Name)) return;
        await Storage.InitializeAsync();
        await Storage.SaveSiteAsync(site);
        Navigation.NavigateTo($"/site/{site.Id}");
