@inject ConnectivityService Connectivity
@inject ISyncService SyncService
@inject NavigationManager Navigation

<div class="app-container">
    <header class="app-header">
        <h1>🏗️ Site Inspector</h1>
    </header>

    <main class="app-main">
        @Body
    </main>

    <nav class="bottom-nav">
        <button class="nav-item @(IsActive("/") ? "active" : "")" @onclick='() => Navigate("/")'>
            <span class="nav-icon">🏠</span>
            <span class="nav-label">Sites</span>
        </button>
        <button class="nav-item @(IsActive("/sync") ? "active" : "")" @onclick="SyncNow">
            <span class="nav-icon">🔄</span>
            <span class="nav-label">Sync</span>
