            {
                <span class="nav-badge">@SyncService.PendingCount</span>
            }
        </button>
    </nav>
</div>

@code {
    protected override void OnInitialized()
    {
        SyncService.OnStatusChanged += _ => InvokeAsync(StateHasChanged);
    }

    private bool IsActive(string path)
    {
        var uri = Navigation.ToBaseRelativePath(Navigation.Uri);
        return path == "/" ? string.IsNullOrEmpty(uri) : uri.StartsWith(path.TrimStart('/'));
    }

    private void Navigate(string path) => Navigation.NavigateTo(path);

    private async Task SyncNow() => await SyncService.SyncAsync();
}

