+        await Storage.InitializeAsync();
+        await Connectivity.InitializeAsync();
+        await LoadData();
+
+        SyncService.OnStatusChanged += _ => InvokeAsync(StateHasChanged);
+        Connectivity.OnConnectivityChanged += async online =>
+        {
+            if (online) await SyncService.SyncAsync();
+            await InvokeAsync(StateHasChanged);
+        };
+    }
+
+    private async Task LoadData()
+    {
+        sites = await Storage.GetSitesAsync();
+        inspectionCounts.Clear();
+        foreach (var site in sites)
+        {
+            var inspections = await Storage.GetInspectionsBySiteAsync(site.Id);
+            inspectionCounts[site.Id] = inspections.Count;
+        }
+    }
+
+    private void NavigateToNewSite() => Navigation.NavigateTo("/site/new");
+    private void NavigateToSite(string id) => Navigation.NavigateTo($"/site/{id}");
+}
+

