+@page "/inspection/{InspectionId}"
+@inject ILocalStorageService Storage
+@inject NavigationManager Navigation
+@inject IJSRuntime JSRuntime
+
+<div class="page-header">
+    <button class="btn-back" @onclick="GoBack">← Back</button>
+    <h1>Inspection</h1>
+</div>
+
+@if (inspection == null)
+{
+    <p class="loading">Loading...</p>
+}
+else
+{
+    <div class="inspection-meta">
+        <p><strong>@inspection.SiteName</strong></p>
+        <p>@inspection.InspectionDate.ToString("MMM dd, yyyy HH:mm")</p>
+        <span class="status-badge @(inspection.Status == InspectionStatus.Completed ? "completed" : "in-progress")">
+            @(inspection.Status == InspectionStatus.Completed ? "Completed" : "In Progress")
+        </span>
+    </div>
+
+    <div class="tabs">
+        <button class="tab @(activeTab == "checklist" ? "active" : "")" @onclick='() => activeTab = "checklist"'>Checklist</button>
+        <button class="tab @(activeTab == "photos" ? "active" : "")" @onclick='() => activeTab = "photos"'>Photos (@inspection.Photos.Count)</button>
+        <button class="tab @(activeTab == "notes" ? "active" : "")" @onclick='() => activeTab = "notes"'>Notes</button>
+    </div>
+
+    @if (activeTab == "checklist")
+    {
+        <div class="checklist-section">
+            @{
+                var categories = inspection.ChecklistItems.GroupBy(i => i.Category);
+            }
+            @foreach (var category in categories)
+            {
+                <h3 class="category-header">@category.Key</h3>
+                @foreach (var item in category)
+                {
+                    <div class="checklist-item">
+                        <p class="checklist-desc">@item.Description</p>
+                        <div class="checklist-buttons">
+                            <button class="check-btn pass @(item.Result == CheckResult.Pass ? "active" : "")"
+                                    @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
+                            <button class="check-btn fail @(item.Result == CheckResult.Fail ? "active" : "")"
+                                    @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
+                            <button class="check-btn na @(item.Result == CheckResult.NotApplicable ? "active" : "")"
+                                    @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
+                        </div>
+                    </div>
+                }
+            }
+        </div>
+    }
+    else if (activeTab == "photos")
+    {
+        <div class="photos-section">
+            <button class="btn-primary btn-full" @onclick="CapturePhoto">📷 Take Photo</button>
+            @foreach (var photo in inspection.Photos)
+            {
+                <div class="photo-card">
+                    <img src="data:@photo.ContentType;base64,@photo.Base64Data" alt="@photo.Caption" class="photo-thumb" />
+                    <input type="text" @bind="photo.Caption" @bind:after="AutoSave" placeholder="Add caption..." class="photo-caption-input" />
+                </div>
+            }
+        </div>
+    }
+    else if (activeTab == "notes")
+    {
+        <div class="notes-section">
+            <textarea class="notes-textarea" @bind="inspection.Notes" @bind:after="AutoSave"
+                      placeholder="Enter inspection notes..."></textarea>
+        </div>
+    }
+
+    @if (inspection.Status != InspectionStatus.Completed)
+    {
+        <button class="btn-success btn-full" @onclick="CompleteInspection">✓ Complete Inspection</button>
+    }
+}
+
+@code {
+    [Parameter] public string InspectionId { get; set; } = "";
+
+    private Inspection? inspection;
+    private string activeTab = "checklist";
+    private IJSObjectReference? cameraModule;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await Storage.InitializeAsync();
+        inspection = await Storage.GetInspectionAsync(InspectionId);
+    }
+
+    private async Task SetResult(ChecklistItem item, CheckResult result)
+    {
+        item.Result = (item.Result == result) ? CheckResult.NotChecked : result;
+        await AutoSave();
+    }
+
+    private async Task AutoSave()
+    {
+        if (inspection != null)
+        {
+            await Storage.SaveInspectionAsync(inspection);
+        }
+    }
+
+    private async Task CapturePhoto()
+    {
+        cameraModule ??= await JSRuntime.InvokeAsync<IJSObjectReference>("import", "./js/camera.js");
+        var result = await cameraModule.InvokeAsync<PhotoCaptureResult?>("capturePhoto");
+        if (result != null && inspection != null)
+        {
+            var photo = new PhotoRecord
+            {
+                FileName = result.FileName,
+                ContentType = result.ContentType,
+                Base64Data = result.Base64Data
+            };
+            inspection.Photos.Add(photo);
+            await AutoSave();
+        }
+    }
+
+    private async Task CompleteInspection()
+    {
+        if (inspection != null)
+        {
+            inspection.Status = InspectionStatus.Completed;
+            await AutoSave();
+        }
+    }
+
+    private void GoBack()
+    {
+        if (inspection != null)
+            Navigation.NavigateTo($"/site/{inspection.SiteId}");
+        else
+            Navigation.NavigateTo("/");
+    }
+
+    private class PhotoCaptureResult
+    {
+        public string FileName { get; set; } = "";
+        public string ContentType { get; set; } = "";
+        public string Base64Data { get; set; } = "";
+    }
+}
