1. const DB_NAME = 'SiteInspectorDb';
2. const DB_VERSION = 1;
3. 
4. let db = null;
5. 
6. export function openDb() {
7.     return new Promise((resolve, reject) => {
8.         if (db) { resolve(true); return; }
9.         const request = indexedDB.open(DB_NAME, DB_VERSION);
10.         request.onupgradeneeded = (event) => {
11.             const database = event.target.result;
12.             if (!database.objectStoreNames.contains('sites')) {
13.                 database.createObjectStore('sites', { keyPath: 'id' });
14.             }
15.             if (!database.objectStoreNames.contains('inspections')) {
16.                 const store = database.createObjectStore('inspections', { keyPath: 'id' });
17.                 store.createIndex('siteId', 'siteId', { unique: false });
18.                 store.createIndex('isSynced', 'isSynced', { unique: false });
19.             }
20.         };
21.         request.onsuccess = (event) => {
22.             db = event.target.result;
23.             resolve(true);
24.         };
25.         request.onerror = (event) => {
26.             reject(event.target.error);
27.         };
28.     });
29. }
30. 
31. export function getAll(storeName) {
32.     return new Promise((resolve, reject) => {
33.         const tx = db.transaction(storeName, 'readonly');
34.         const store = tx.objectStore(storeName);
35.         const request = store.getAll();
36.         request.onsuccess = () => resolve(request.result);
37.         request.onerror = () => reject(request.error);
38.     });
39. }
40. 
41. export function getById(storeName, id) {
42.     return new Promise((resolve, reject) => {
43.         const tx = db.transaction(storeName, 'readonly');
44.         const store = tx.objectStore(storeName);
45.         const request = store.get(id);
46.         request.onsuccess = () => resolve(request.result || null);
47.         request.onerror = () => reject(request.error);
48.     });
49. }
50.

